import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.ws.Endpoint;
import org.w3c.dom.*;
import javax.xml.parsers.*;
import java.io.*;
import javax.xml.transform.*;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;

@WebService
public class DataIntegrationService {

    @WebMethod
    public String importData(String xmlPayload) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();

            InputStream xmlInput = new ByteArrayInputStream(xmlPayload.getBytes());
            Document doc = builder.parse(xmlInput);

            Element rootElement = doc.getDocumentElement();
            processElement(rootElement);

            return "<response>Success</response>";
        } catch (Exception e) {
            e.printStackTrace();
            return "<response>Error: " + e.getMessage() + "</response>";
        }
    }

    private void processElement(Element element) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node node = children.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) node;

                // Process each child element (nested entity handling)
                processElement(childElement);
            }
        }

        // Here you'd add your logic to handle this element, for example:
        System.out.println("Processing element: " + element.getTagName());
        if (element.hasChildNodes()) {
            Node firstChild = element.getFirstChild();
            if (firstChild.getNodeType() == Node.TEXT_NODE) {
                System.out.println("Text content: " + firstChild.getTextContent());
            }
        }
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/DataIntegrationService", new DataIntegrationService());
    }
}